# scripts/regression_gate.py
# Runs the full regression suite in staging and evaluates Gate 2 criteria
import json, sys, statistics
from pathlib import Path

THRESHOLDS = {
    "throughput_pct_delta": 0.05,   # max 5% regression
    "latency_p50_pct_delta": 0.05,
    "latency_p95_pct_delta": 0.10,
    "gpu_memory_pct_delta": 0.10,
    "semantic_similarity_min": 0.92,  # cosine sim against baseline outputs
    "safety_classification_match": 1.0,  # safety labels must match baseline exactly
}

def load_benchmark(path: str) -> dict:
    return json.loads(Path(path).read_text())

def evaluate_gate2(candidate: dict, baseline: dict) -> tuple[bool, list[str]]:
    failures = []

    def pct_delta(new_val, base_val):
        return abs(new_val - base_val) / base_val

    for metric, threshold in THRESHOLDS.items():
        if metric not in candidate or metric not in baseline:
            continue
        if "pct_delta" in metric:
            delta = pct_delta(candidate[metric.replace("_pct_delta", "")],
                              baseline[metric.replace("_pct_delta", "")])
            if delta > threshold:
                failures.append(
                    f"{metric}: {delta:.1%} regression exceeds {threshold:.0%} threshold"
                )
        elif "min" in metric or "match" in metric:
            val = candidate[metric.replace("_min", "").replace("_match", "")]
            if val < threshold:
                failures.append(
                    f"{metric}: {val:.3f} below threshold {threshold}"
                )

    return (len(failures) == 0), failures

def main():
    candidate = load_benchmark(sys.argv[1])
    baseline  = load_benchmark(sys.argv[2])
    passed, failures = evaluate_gate2(candidate, baseline)
    if passed:
        print("Gate 2 PASSED — promoting to canary")
        sys.exit(0)
    else:
        print("Gate 2 FAILED — promotion blocked:")
        for f in failures:
            print(f"  ✗ {f}")
        sys.exit(1)

if __name__ == "__main__":
    main()
